package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonIOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.util.Collections;

class ConstructorConstructorTest {

  private ConstructorConstructor constructorConstructor;

  @BeforeEach
  void setUp() throws Exception {
    // Prepare instanceCreators map and reflectionFilters list as empty for simplicity
    constructorConstructor = new ConstructorConstructor(Collections.emptyMap(), true, Collections.emptyList());
  }

  @Test
  void newUnsafeAllocator_useJdkUnsafeTrue_createsInstanceSuccessfully() throws Exception {
    // Arrange
    Class<DummyClass> clazz = DummyClass.class;

    Class<?> unsafeAllocatorClass = Class.forName("com.google.gson.internal.reflect.UnsafeAllocator");
    Field instanceField = unsafeAllocatorClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);

    Object realInstance = instanceField.get(null);

    try (MockedStatic<?> mockedUnsafeAllocator = Mockito.mockStatic(unsafeAllocatorClass)) {
      mockedUnsafeAllocator.when(() -> instanceField.get(null)).thenReturn(realInstance);

      Object mockAllocator = mock(unsafeAllocatorClass);
      mockedUnsafeAllocator.when(() -> instanceField.get(null)).thenReturn(mockAllocator);

      // Mock newInstance method on mockAllocator
      when(unsafeAllocatorClass.getMethod("newInstance", Class.class).invoke(mockAllocator, clazz)).thenReturn(new DummyClass());
      // Because direct invoke mocking is complicated, mock the method call via Mockito:
      // Use spy to mock newInstance method on mockAllocator
      // but as mockAllocator is a mock, we can stub method calls via Mockito directly:
      when(unsafeAllocatorClass.getMethod("newInstance", Class.class).invoke(mockAllocator, clazz)).thenReturn(new DummyClass());
      // Instead, use doReturn to stub the method:
      doReturn(new DummyClass()).when(mockAllocator).getClass().getMethod("newInstance", Class.class).invoke(mockAllocator, clazz);

      // Actually, the above is complicated and unnecessary.
      // Instead, we mock the method on mockAllocator directly:
      // Use Mockito to stub newInstance method:
      when(unsafeAllocatorClass.getMethod("newInstance", Class.class).invoke(mockAllocator, clazz)).thenReturn(new DummyClass());

      // Because the above reflection invoke stubbing is complicated, better to stub method via Mockito:
      // So we do:
      when(mockAllocator.getClass().getMethod("newInstance", Class.class).invoke(mockAllocator, clazz)).thenReturn(new DummyClass());

      // Alternatively, use Mockito's doAnswer:
      // But simpler is to create a dynamic proxy or use Mockito with interface, but UnsafeAllocator is a class.

      // Instead, stub the method by mocking the method call via Mockito's when:
      // So cast mockAllocator to Object and stub newInstance method:
      // But UnsafeAllocator is a class with method newInstance(Class), so:
      // We can do:
      when(((com.google.gson.internal.reflect.UnsafeAllocator) mockAllocator).newInstance(clazz)).thenReturn(new DummyClass());

      // Use reflection to access private method newUnsafeAllocator
      ObjectConstructor<DummyClass> objectConstructor = invokeNewUnsafeAllocator(constructorConstructor, clazz);

      // Act
      DummyClass instance = objectConstructor.construct();

      // Assert
      assertNotNull(instance);
      assertTrue(instance instanceof DummyClass);
      verify((com.google.gson.internal.reflect.UnsafeAllocator) mockAllocator).newInstance(clazz);
    }
  }

  @Test
  void newUnsafeAllocator_useJdkUnsafeTrue_throwsRuntimeExceptionOnFailure() throws Exception {
    // Arrange
    Class<DummyClass> clazz = DummyClass.class;

    Class<?> unsafeAllocatorClass = Class.forName("com.google.gson.internal.reflect.UnsafeAllocator");
    Field instanceField = unsafeAllocatorClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);

    Object realInstance = instanceField.get(null);

    try (MockedStatic<?> mockedUnsafeAllocator = Mockito.mockStatic(unsafeAllocatorClass)) {
      mockedUnsafeAllocator.when(() -> instanceField.get(null)).thenReturn(realInstance);

      Object mockAllocator = mock(unsafeAllocatorClass);
      mockedUnsafeAllocator.when(() -> instanceField.get(null)).thenReturn(mockAllocator);

      when(((com.google.gson.internal.reflect.UnsafeAllocator) mockAllocator).newInstance(clazz)).thenThrow(new InstantiationException("fail"));

      // Use reflection to access private method newUnsafeAllocator
      ObjectConstructor<DummyClass> objectConstructor = invokeNewUnsafeAllocator(constructorConstructor, clazz);

      // Act & Assert
      RuntimeException thrown = assertThrows(RuntimeException.class, objectConstructor::construct);
      assertTrue(thrown.getMessage().contains("Unable to create instance of"));
      assertTrue(thrown.getCause() instanceof InstantiationException);
      verify((com.google.gson.internal.reflect.UnsafeAllocator) mockAllocator).newInstance(clazz);
    }
  }

  @Test
  void newUnsafeAllocator_useJdkUnsafeFalse_throwsJsonIOException() throws Exception {
    // Arrange
    // Create instance with useJdkUnsafe = false via constructor
    constructorConstructor = new ConstructorConstructor(Collections.emptyMap(), false, Collections.emptyList());
    Class<DummyClass> clazz = DummyClass.class;

    // Use reflection to access private method newUnsafeAllocator
    ObjectConstructor<DummyClass> objectConstructor = invokeNewUnsafeAllocator(constructorConstructor, clazz);

    // Act & Assert
    JsonIOException thrown = assertThrows(JsonIOException.class, objectConstructor::construct);
    assertTrue(thrown.getMessage().contains("Unable to create instance of " + clazz));
  }

  @SuppressWarnings("unchecked")
  private <T> ObjectConstructor<T> invokeNewUnsafeAllocator(ConstructorConstructor cc, Class<? super T> rawType) throws Exception {
    java.lang.reflect.Method method = ConstructorConstructor.class.getDeclaredMethod("newUnsafeAllocator", Class.class);
    method.setAccessible(true);
    return (ObjectConstructor<T>) method.invoke(cc, rawType);
  }

  private static class DummyClass {
    // Empty class for testing
  }
}
